const raw = $input.first().json.body.imageBase64;

// Remove o prefixo data:...;base64,
const base64Clean = raw.includes(',') ? raw.split(',')[1] : raw;
const mimeType = raw.startsWith('data:') 
  ? raw.split(';')[0].replace('data:', '') 
  : 'image/jpeg';

return [{
  json: {
    body: {
      model: "claude-opus-4-5-20251101",
      max_tokens: 4096,
      messages: [{
        role: "user",
        content: [
          {
            type: "image",
            source: {
              type: "base64",
              media_type: mimeType,
              data: base64Clean
            }
          },
          {
            type: "text",
            text: "Analise este criativo de marketing e converta em HTML+CSS fiel. Use variáveis CSS (:root) para preço, textos e cores. Retorne apenas o código HTML completo."
          }
        ]
      }]
    }
  }
}];

let html = $input.first().json.content[0].text;
html = html.replace(/```html\n?/g, '').replace(/```\n?/g, '').trim();
return [{ json: { html } }];

