return items.map(item => {
  // 1️⃣ Parse do campo "output" (string → objeto)
  const parsed = JSON.parse(item.json.output);

  let html = parsed.html;

  // 2️⃣ Corrigir HTML escapado
  html = html
    .replace(/\\n/g, '\n')
    .replace(/\\"/g, '"')
    .replace(/&amp;/g, '&');

  // 3️⃣ Garantir placeholders
  const placeholders = parsed.placeholders || [];

  return {
    json: {
      html,
      placeholders
    }
  };
});

